Gráfico con facetas y repeat

alt.Chart(movies_cleaned).mark_boxplot().encode(
    alt.X('Running_Time_min', type='quantitative'),
    alt.Y(alt.repeat('row'), type='nominal'),
    alt.Size('count()')
).facet(
    column='MPAA_Rating'
).repeat(
    row=categorical_filtered
)

Merge de los 2 DS: geojson + df data.unemployment

alt.Chart(gdf_us_counties).mark_geoshape().transform_lookup(
    lookup='id',
    from_=alt.LookupData(data=df_us_unemp, key='id', fields=['rate'])
).encode(
    alt.Color('rate:Q')
).project(
    type='albersUsa'
)

alt.Chart(movies_extended).mark_bar().encode(
    alt.X(
        'Worldwide_Gross',
        bin=alt.BinParams(
            maxbins=30
        )
    ),
    alt.Y('count()'),
    alt.Color('Major_Genre')
)

alt.Chart(movies_extended).mark_rect().encode(
    alt.X(
        'Worldwide_Gross',
        bin=alt.BinParams(
            maxbins=10
        )
    ),
    alt.Y('Major_Genre'),
    alt.Color('count()')
)
